<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***APIDocumentationGeneratorforSPRIN*GeneratesOpenAPI3.0/Swaggerdocumentation*/classAPIDocumentation{private$baseUrl;private$version;publicfunction__construct(){require_once__DIR__.'/config.php';$this->baseUrl=BASE_URL.'/api';$this->version=API_VERSION??'v1';}/***GenerateOpenAPIspecification*/publicfunctiongenerateSpec(){return['openapi'=>'3.0.0','info'=>$this->getInfo(),'servers'=>$this->getServers(),'paths'=>$this->getPaths(),'components'=>$this->getComponents(),'security'=>[['bearerAuth'=>[]]],'tags'=>$this->getTags()];}/***APIInformation*/privatefunctiongetInfo(){return['title'=>'SPRINAPI','description'=>'SistemPersonildanJadwalPolresSamosir-RESTAPIDocumentation','version'=>$this->version,'contact'=>['name'=>'POLRESSamosir-BagianOperasional','email'=>'bagops@polressamosir.go.id'],'license'=>['name'=>'Private','url'=>'https://polressamosir.go.id']];}/***APIServers*/privatefunctiongetServers(){return[['url'=>$this->baseUrl,'description'=>'LocalDevelopmentServer'],['url'=>'https://api.polressamosir.go.id/v1','description'=>'ProductionServer']];}/***APIPaths(Endpoints)*/privatefunctiongetPaths(){return[/Authentication'/auth/login'=>['post'=>['tags'=>['Authentication'],'summary'=>'Userlogin','description'=>'Authenticateuserwithusernameandpassword','requestBody'=>['required'=>true,'content'=>['application/json'=>['schema'=>['type'=>'object','required'=>['username','password'],'properties'=>['username'=>['type'=>'string','example'=>'bagops'],'password'=>['type'=>'string','format'=>'password','example'=>'admin123']]]]]],'responses'=>['200'=>['description'=>'Loginsuccessful','content'=>['application/json'=>['schema'=>['$ref'=>'#/components/schemas/LoginResponse']]]],'401'=>['description'=>'Invalidcredentials']]]],/Personil'/personil'=>['get'=>['tags'=>['Personil'],'summary'=>'Getpersonillist','description'=>'Retrievelistofpersonilwithoptionalfilters','parameters'=>[['name'=>'unsur','in'=>'query','schema'=>['type'=>'string'],'description'=>'Filterbyunsurkode'],['name'=>'bagian','in'=>'query','schema'=>['type'=>'integer'],'description'=>'FilterbybagianID'],['name'=>'search','in'=>'query','schema'=>['type'=>'string'],'description'=>'SearchbynameorNRP'],['name'=>'page','in'=>'query','schema'=>['type'=>'integer','default'=>1],'description'=>'Pagenumber'],['name'=>'limit','in'=>'query','schema'=>['type'=>'integer','default'=>100],'description'=>'Itemsperpage']],'responses'=>['200'=>['description'=>'Personillist','content'=>['application/json'=>['schema'=>['$ref'=>'#/components/schemas/PersonilListResponse']]]]]],'post'=>['tags'=>['Personil'],'summary'=>'Createpersonil','description'=>'Createnewpersonilrecord','requestBody'=>['required'=>true,'content'=>['application/json'=>['schema'=>['$ref'=>'#/components/schemas/PersonilCreate']]]],'responses'=>['201'=>['description'=>'Personilcreatedsuccessfully'],'400'=>['description'=>'Invalidinputdata']]]],'/personil/{id}'=>['get'=>['tags'=>['Personil'],'summary'=>'GetpersonilbyID','parameters'=>[['name'=>'id','in'=>'path','required'=>true,'schema'=>['type'=>'integer'],'description'=>'PersonilID']],'responses'=>['200'=>['description'=>'Personildetails','content'=>['application/json'=>['schema'=>['$ref'=>'#/components/schemas/Personil']]]],'404'=>['description'=>'Personilnotfound']]],'put'=>['tags'=>['Personil'],'summary'=>'Updatepersonil','parameters'=>[['name'=>'id','in'=>'path','required'=>true,'schema'=>['type'=>'integer']]],'requestBody'=>['required'=>true,'content'=>['application/json'=>['schema'=>['$ref'=>'#/components/schemas/PersonilUpdate']]]],'responses'=>['200'=>['description'=>'Personilupdated']]],'delete'=>['tags'=>['Personil'],'summary'=>'Deletepersonil','parameters'=>[['name'=>'id','in'=>'path','required'=>true,'schema'=>['type'=>'integer']]],'responses'=>['204'=>['description'=>'Personildeleted']]]],/Statistics'/stats/unsur'=>['get'=>['tags'=>['Statistics'],'summary'=>'Getunsurstatistics','description'=>'Retrievepersonildistributionbyunsur','responses'=>['200'=>['description'=>'Unsurstatistics','content'=>['application/json'=>['schema'=>['$ref'=>'#/components/schemas/UnsurStatsResponse']]]]]]],/Export'/export/personil'=>['get'=>['tags'=>['Export'],'summary'=>'Exportpersonildata','parameters'=>[['name'=>'format','in'=>'query','required'=>true,'schema'=>['type'=>'string','enum'=>['xlsx','pdf','csv']],'description'=>'Exportformat'],['name'=>'unsur','in'=>'query','schema'=>['type'=>'string'],'description'=>'Filterbyunsur']],'responses'=>['200'=>['description'=>'Exportfile']]]],/Search'/search'=>['get'=>['tags'=>['Search'],'summary'=>'Advancedsearch','parameters'=>[['name'=>'q','in'=>'query','required'=>true,'schema'=>['type'=>'string'],'description'=>'Searchquery'],['name'=>'type','in'=>'query','schema'=>['type'=>'string','enum'=>['personil','bagian','unsur'],'default'=>'personil']]],'responses'=>['200'=>['description'=>'Searchresults']]]]];}/***APIComponents(Schemas,Security)*/privatefunctiongetComponents(){return['schemas'=>[/PersonilSchema'Personil'=>['type'=>'object','properties'=>['id'=>['type'=>'integer'],'nama'=>['type'=>'string'],'nama_lengkap'=>['type'=>'string'],'nrp'=>['type'=>'string'],'gelar_pendidikan'=>['type'=>'string'],'JK'=>['type'=>'string','enum'=>['L','P']],'status_nikah'=>['type'=>'string'],'status_ket'=>['type'=>'string'],'nama_pangkat'=>['type'=>'string'],'nama_jabatan'=>['type'=>'string'],'nama_bagian'=>['type'=>'string'],'nama_unsur'=>['type'=>'string'],'status_kepegawaian'=>['type'=>'string'],'created_at'=>['type'=>'string','format'=>'date-time']]],'PersonilCreate'=>['type'=>'object','required'=>['nama','nrp','id_pangkat','id_jabatan','id_bagian'],'properties'=>['nama'=>['type'=>'string'],'nrp'=>['type'=>'string'],'id_pangkat'=>['type'=>'integer'],'id_jabatan'=>['type'=>'integer'],'id_bagian'=>['type'=>'integer'],'id_unsur'=>['type'=>'integer'],'JK'=>['type'=>'string','enum'=>['L','P']]]],'PersonilUpdate'=>['type'=>'object','properties'=>['nama'=>['type'=>'string'],'nrp'=>['type'=>'string'],'id_pangkat'=>['type'=>'integer'],'id_jabatan'=>['type'=>'integer'],'id_bagian'=>['type'=>'integer'],'status_ket'=>['type'=>'string']]],'PersonilListResponse'=>['type'=>'object','properties'=>['success'=>['type'=>'boolean'],'data'=>['type'=>'array','items'=>['$ref'=>'#/components/schemas/Personil']],'pagination'=>['type'=>'object','properties'=>['total'=>['type'=>'integer'],'page'=>['type'=>'integer'],'limit'=>['type'=>'integer'],'total_pages'=>['type'=>'integer']]]]],/LoginSchema'LoginResponse'=>['type'=>'object','properties'=>['success'=>['type'=>'boolean'],'message'=>['type'=>'string'],'data'=>['type'=>'object','properties'=>['token'=>['type'=>'string'],'user'=>['type'=>'object','properties'=>['id'=>['type'=>'integer'],'username'=>['type'=>'string'],'name'=>['type'=>'string']]]]]]],/StatisticsSchema'UnsurStatsResponse'=>['type'=>'object','properties'=>['success'=>['type'=>'boolean'],'data'=>['type'=>'object','properties'=>['unsur'=>['type'=>'array','items'=>['type'=>'object','properties'=>['kode_unsur'=>['type'=>'string'],'nama_unsur'=>['type'=>'string'],'total_personil'=>['type'=>'integer'],'polri_count'=>['type'=>'integer'],'asn_count'=>['type'=>'integer'],'p3k_count'=>['type'=>'integer']]]],'total_all'=>['type'=>'integer']]]]],/ErrorSchema'Error'=>['type'=>'object','properties'=>['success'=>['type'=>'boolean','example'=>false],'message'=>['type'=>'string'],'errors'=>['type'=>'object','additionalProperties'=>true]]]],'securitySchemes'=>['bearerAuth'=>['type'=>'http','scheme'=>'bearer','bearerFormat'=>'JWT','description'=>'JWTtokenobtainedfrom/auth/login']]];}/***APITags*/privatefunctiongetTags(){return[['name'=>'Authentication','description'=>'Userlogin,logout,andtokenmanagement'],['name'=>'Personil','description'=>'PersonilCRUDoperationsandmanagement'],['name'=>'Statistics','description'=>'Dashboardstatisticsandreports'],['name'=>'Export','description'=>'Dataexportfunctionality(PDF,Excel,CSV)'],['name'=>'Search','description'=>'Advancedsearchwithfilters']];}/***GenerateandsaveSwaggerJSON*/publicfunctiongenerateDocs($outputPath=null){$outputPath=$outputPath??__DIR__.'/../public/api-docs/swagger.json';$spec=$this->generateSpec();/Createdirectoryifnotexists$dir=dirname($outputPath);if(!is_dir($dir)){mkdir($dir,0755,true);}file_put_contents($outputPath,json_encode($spec,JSON_PRETTY_PRINT|JSON_UNESCAPED_SLASHES));return['success'=>true,'path'=>$outputPath,'url'=>str_replace(__DIR__.'/../','/',$outputPath)];}/***GetSwaggerUIHTML*/publicfunctiongetSwaggerUI(){return'<!DOCTYPEhtml><htmllang="en"><head><metacharset="UTF-8"><title>SPRINAPIDocumentation</title><linkrel="stylesheet"type="text/css"href="https://unpkg.com/swagger-ui-dist@3/swagger-ui.css"/><style>body{margin:0;padding:0;}#swagger-ui{max-width:1460px;margin:0auto;}.topbar{display:none;}</style></head><body><divid="swagger-ui"></div><scriptsrc="https://unpkg.com/swagger-ui-dist@3/swagger-ui-bundle.js"></script><scriptsrc="https://unpkg.com/swagger-ui-dist@3/swagger-ui-standalone-preset.js"></script><script>window.onload=function(){constui=SwaggerUIBundle({url:"swagger.json",dom_id:"#swagger-ui",deepLinking:true,presets:[SwaggerUIBundle.presets.apis,SwaggerUIStandalonePreset],plugins:[SwaggerUIBundle.plugins.DownloadUrl],layout:"StandaloneLayout",validatorUrl:null});};</script></body></html>';}/***GenerateandsaveSwaggerUI*/publicfunctiongenerateSwaggerUI($outputPath=null){$outputPath=$outputPath??__DIR__.'/../public/api-docs/index.html';$dir=dirname($outputPath);if(!is_dir($dir)){mkdir($dir,0755,true);}file_put_contents($outputPath,$this->getSwaggerUI());return['success'=>true,'path'=>$outputPath,'url'=>str_replace(__DIR__.'/../','/',$outputPath)];}/***Generatecompletedocumentation*/publicfunctiongenerateAll(){return['swagger_json'=>$this->generateDocs(),'swagger_ui'=>$this->generateSwaggerUI(),'access_url'=>'/api-docs/','api_base'=>$this->baseUrl];}}?>
